// Merge & Transform Data for Client Initiation
// This node combines Pipedrive and Google Sheets data into ElevenLabs format

const startTime = $('Extract & Validate Call Metadata').first().json.start_time || Date.now();
const callerId = $('Extract & Validate Call Metadata').first().json.caller_id || '';

// Extract Pipedrive data (if successful)
let pipedriveData = null;
try {
  const pipedriveNode = $('Pipedrive: Lookup Person').all();
  if (pipedriveNode.length > 0 && pipedriveNode[0].json?.data?.items?.length > 0) {
    const person = pipedriveNode[0].json.data.items[0].item;
    pipedriveData = {
      id: person.id,
      name: person.name,
      first_name: person.first_name || person.name?.split(' ')[0],
      org_name: person.organization?.name || '',
      org_id: person.organization?.id || 0,
      account_tier: person.custom_fields?.account_tier || null,
      industry: person.custom_fields?.industry || ''
    };
  }
} catch (e) {
  console.log('Pipedrive lookup failed or no results:', e.message);
}

// Extract Sheets data (if successful)
let sheetsData = null;
try {
  const sheetsNode = $('Google Sheets: Lookup Call History').all();
  if (sheetsNode.length > 0 && sheetsNode[0].json) {
    const row = sheetsNode[0].json;
    sheetsData = {
      row_number: row.row || 0,
      name: row.name || '',
      call_count: parseInt(row.call_count) || 0,
      last_interaction: row.last_interaction || '',
      last_topic: row.last_topic || '',
      notes: row.notes || ''
    };
  }
} catch (e) {
  console.log('Sheets lookup failed or no results:', e.message);
}

// Sanitize function to remove PII patterns
function sanitize(text) {
  if (!text) return '';
  // Remove SSN patterns
  text = text.replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED]');
  // Remove credit card patterns
  text = text.replace(/\b\d{16}\b/g, '[REDACTED]');
  // Truncate long strings
  if (text.length > 200) {
    text = text.substring(0, 197) + '...';
  }
  return text;
}

// Calculate account tier if not in Pipedrive
function calculateTier(callCount) {
  if (callCount === 0) return 'New';
  if (callCount <= 5) return 'Bronze';
  if (callCount <= 15) return 'Silver';
  return 'Gold';
}

// Merge data with priority: field-level merge, most recent/Pipedrive > Sheets
const customerName = pipedriveData?.name || sheetsData?.name || 'there';
const customerFirstName = pipedriveData?.first_name || sheetsData?.name?.split(' ')[0] || 'there';
const company = pipedriveData?.org_name || '';
const industry = pipedriveData?.industry || '';
const interactionCount = sheetsData?.call_count || 0;
const accountTier = pipedriveData?.account_tier || calculateTier(interactionCount);
const callHistory = sheetsData?.last_interaction || 'First-time caller';
const lastTopic = sheetsData?.last_topic || '';
const notes = sanitize(sheetsData?.notes || '');

const lookupSuccess = !!(pipedriveData || sheetsData);
const dataSource = pipedriveData ? 'pipedrive' : (sheetsData ? 'sheets' : 'none');

// Build dynamic variables object
const dynamicVariables = {
  customer_name: customerName,
  customer_first_name: customerFirstName,
  company: company,
  industry: industry,
  account_tier: accountTier,
  call_history: callHistory,
  interaction_count: interactionCount,
  last_topic: lastTopic,
  notes: notes,
  lookup_success: lookupSuccess,
  data_source: dataSource,
  secret__pipedrive_person_id: pipedriveData?.id || 0,
  secret__pipedrive_org_id: pipedriveData?.org_id || 0,
  secret__google_sheet_row: sheetsData?.row_number || 0
};

// Build conversation config override (for VIP/returning customers)
let conversationConfigOverride = null;

if (accountTier === 'Gold') {
  // VIP greeting
  conversationConfigOverride = {
    agent: {
      first_message: `Hi ${customerFirstName}, this is Sarah from Wranngle. I see you're one of our premium clients - how can I help you today?`
    }
  };
} else if (interactionCount >= 3) {
  // Returning customer greeting
  conversationConfigOverride = {
    agent: {
      first_message: `Hi ${customerFirstName}, great to hear from you again! This is Sarah from Wranngle.`
    }
  };
}

// Calculate execution time
const executionTime = Date.now() - startTime;

// Build final response
const response = {
  type: 'conversation_initiation_client_data',
  dynamic_variables: dynamicVariables,
  ...(conversationConfigOverride && { conversation_config_override: conversationConfigOverride })
};

// Build metadata for logging
const metadata = {
  caller_id: callerId,
  execution_time_ms: executionTime,
  pipedrive_success: !!pipedriveData,
  sheets_success: !!sheetsData,
  enrichment_success: lookupSuccess,
  account_tier: accountTier,
  data_source: dataSource
};

return [
  {
    json: {
      response: response,
      metadata: metadata
    }
  }
];

